function _cancelOrder(address nftAddress, uint256 assetId) internal returns (Order memory) {
  address sender = _msgSender();
  Order memory order = orderByAssetId[nftAddress][assetId];

  require(order.id != 0, "Asset not published");
  require(order.seller == sender || sender == owner(), "Unauthorized user");

  bytes32 orderId = order.id;
  address orderSeller = order.seller;
  address orderNftAddress = order.nftAddress;
  delete orderByAssetId[nftAddress][assetId];

  emit OrderCancelled(
    orderId,
    assetId,
    orderSeller,
    orderNftAddress
  );

  return order;
}

function _initialize(
    address _defaultAdmin,
    address _nodeOperatorManager,
    address _feeRecipient,
    uint256 _feeRate,
    uint256 _confirmExpiry
) internal {
    _requireNotZero(_nodeOperatorManager);

    super._initialize(_defaultAdmin, _confirmExpiry);

    _setFeeRate(_feeRate);
    _setFeeRecipient(_feeRecipient);

    _grantRole(NODE_OPERATOR_MANAGER_ROLE, _nodeOperatorManager);
    _setRoleAdmin(NODE_OPERATOR_MANAGER_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_FEE_EXEMPT_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_UNGUARANTEED_DEPOSIT_ROLE, NODE_OPERATOR_MANAGER_ROLE);
    _setRoleAdmin(NODE_OPERATOR_PROVE_UNKNOWN_VALIDATOR_ROLE, NODE_OPERATOR_MANAGER_ROLE);
}

function royaltyInfo(
    uint256 tokenId,
    uint256 salePrice
) public view virtual returns (address receiver, uint256 amount) {
    ERC2981Storage storage $ = _getERC2981Storage();
    RoyaltyInfo storage _royaltyInfo = $._tokenRoyaltyInfo[tokenId];
    address royaltyReceiver = _royaltyInfo.receiver;
    uint96 royaltyFraction = _royaltyInfo.royaltyFraction;

    if (royaltyReceiver == address(0)) {
        royaltyReceiver = $._defaultRoyaltyInfo.receiver;
        royaltyFraction = $._defaultRoyaltyInfo.royaltyFraction;
    }

    uint256 royaltyAmount = (salePrice * royaltyFraction) / _feeDenominator();

    return (royaltyReceiver, royaltyAmount);
}

function _checkCanCall(address caller, bytes calldata data) internal virtual {
    AccessManagedStorage storage $ = _getAccessManagedStorage();
    (bool immediate, uint32 delay) = AuthorityUtils.canCallWithDelay(
        authority(),
        caller,
        address(this),
        bytes4(data[0:4])
    );
    if (!immediate) {
        if (delay > 0) {
            $._consumingSchedule = true;
            IAccessManager(authority()).consumeScheduledOp(caller, data);
            $._consumingSchedule = false;
        } else {
            revert AccessManagedUnauthorized(caller);
        }
    }
}

function _release(IERC20Upgradeable token, address account) internal returns (uint256) {
    require(shares(account) > 0, "PaymentSplitter: account has no shares");

    uint256 totalReceived = token.balanceOf(address(this)) + totalReleased(token);
    uint256 payment = _pendingPayment(account, totalReceived, released(token, account));

    if (payment == 0) {
        return 0;
    }

    _erc20Released[token][account] += payment;
    _erc20TotalReleased[token] += payment;

    SafeERC20Upgradeable.safeTransfer(token, account, payment);
    emit ERC20PaymentReleased(token, account, payment);

    return payment;
}

function _transfer(address sender, address recipient, uint256 amount) internal virtual {
    require(sender != address(0), "ERC20: transfer from the zero address");
    require(recipient != address(0), "ERC20: transfer to the zero address");

    _beforeTokenTransfer(sender, recipient, amount);

    uint256 senderBalance = _balances[sender];
    require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
    unchecked {
        _balances[sender] = senderBalance - amount;
    }
    _balances[recipient] += amount;

    emit Transfer(sender, recipient, amount);
}

function registerBalance() external {
  require(!registeredBalance[msg.sender], "Register Balance::The user is already registered");

  // Get balance of the sender
  uint256 currentBalance = estateLandBalance.balanceOf(msg.sender);
  if (currentBalance > 0) {
    require(
      estateLandBalance.destroyTokens(msg.sender, currentBalance),
      "Register Balance::Could not destroy tokens"
    );
  }

  // Set balance as registered
  registeredBalance[msg.sender] = true;

  // Get LAND balance
  uint256 newBalance = getLANDsSize(msg.sender);

  // Generate Tokens
  require(
    estateLandBalance.generateTokens(msg.sender, newBalance),
    "Register Balance::Could not generate tokens"
  );
}

function submitRewardsForInterval(uint32 interval) external onlyOwner {
    require(!intervalSubmitted[interval], "Interval already submitted");
    require(interval <= this.getCurrentInterval(), "Interval not finished");
    address[] memory operators = operatorsInInterval[interval].values();
    require(operators.length > 0, "No operators to reward");
    address[] memory strategies = strategiesInInterval[interval].values();
    require(strategies.length > 0, "No strategies used in the interval");

    for (uint256 i = 0; i < strategies.length; i++) {
        _submitRewardsForStrategy(interval, IStrategy(strategies[i]), operators);
    }

    intervalSubmitted[interval] = true;
    emit RewardsSubmittedForInterval(interval, operators.length);
}

function withdrawStake(uint256 _unbondingLockId) external whenSystemNotPaused currentRoundInitialized {
    Delegator storage del = delegators[msg.sender];
    UnbondingLock storage lock = del.unbondingLocks[_unbondingLockId];

    require(isValidUnbondingLock(msg.sender, _unbondingLockId), "invalid unbonding lock ID");
    require(
        lock.withdrawRound <= roundsManager().currentRound(),
        "withdraw round must be before or equal to the current round"
    );

    uint256 amount = lock.amount;
    uint256 withdrawRound = lock.withdrawRound;
    // Delete unbonding lock
    delete del.unbondingLocks[_unbondingLockId];

    // Tell Minter to transfer stake (LPT) to the delegator
    minter().trustedTransferTokens(msg.sender, amount);

    emit WithdrawStake(msg.sender, _unbondingLockId, amount, withdrawRound);
}

function buyOne() external payable nonReentrant returns (uint256) {
    uint256 amountPaidInWei = msg.value;
    require(amountPaidInWei > 0, "Amount paid must be greater than zero");

    // Price should be in [wei / NFT]
    uint256 currentPriceInWei = oracle.getMedianPrice(token.symbol());
    require(amountPaidInWei >= currentPriceInWei, "Amount paid is not enough");

    uint256 tokenId = token.mint(msg.sender);

    msg.sender.sendValue(amountPaidInWei - currentPriceInWei);

    emit TokenBought(msg.sender, tokenId, currentPriceInWei);

    return tokenId;
}

function _consumeScheduledOp(bytes32 operationId) internal virtual returns (uint32) {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    uint48 timepoint = $._schedules[operationId].timepoint;
    uint32 nonce = $._schedules[operationId].nonce;

    if (timepoint == 0) {
        revert AccessManagerNotScheduled(operationId);
    } else if (timepoint > Time.timestamp()) {
        revert AccessManagerNotReady(operationId);
    } else if (_isExpired(timepoint)) {
        revert AccessManagerExpired(operationId);
    }

    delete $._schedules[operationId].timepoint; // reset the timepoint, keep the nonce
    emit OperationExecuted(operationId, nonce);

    return nonce;
}

