function deployCounterpartToken(TokenDescription memory tokenDesc, uint256 height, bytes memory proof)
        external
        returns (address deployedToken)
    {
        bytes32 id = _generateTokenDescriptionId(tokenDesc);
        require(!_processed[id], CounterpartTokenAlreadyDeployed());
        require(
            _counterpartTokens[tokenDesc.originalToken] == address(0),
            "Counterpart token already exists for this original token"
        );

        signalService.verifySignal(height, trustedCommitmentPublisher, counterpart, id, proof);

        deployedToken = address(new BridgedERC1155(tokenDesc.uri, tokenDesc.originalToken));
        _counterpartTokens[tokenDesc.originalToken] = deployedToken;
        _isBridgedTokens[deployedToken] = true;
        _processed[id] = true;

        emit CounterpartTokenDeployed(id, tokenDesc, deployedToken);
    }

function _prefund(
    PackedUserOperation calldata userOp,
    bytes32 userOpHash,
    IERC20 token,
    uint256 tokenPrice,
    address prefunder_,
    uint256 maxCost
)
    internal
    virtual
    override
    returns (bool prefunded, uint256 prefundAmount, address prefunder, bytes memory prefundContext)
{
    address guarantor = _fetchGuarantor(userOp);
    bool isGuaranteed = guarantor != address(0);
    (prefunded, prefundAmount, prefunder, prefundContext) = super._prefund(
        userOp,
        userOpHash,
        token,
        tokenPrice,
        isGuaranteed ? guarantor : prefunder_,
        maxCost + (isGuaranteed ? 0 : _guaranteedPostOpCost())
    );
    if (prefunder == guarantor) {
        emit UserOperationGuaranteed(userOpHash, prefunder, prefundAmount);
    }
    return (prefunded, prefundAmount, prefunder, abi.encodePacked(prefundContext, userOp.sender));
}

function _afterSwap(address, PoolKey calldata key, SwapParams calldata params, BalanceDelta, bytes calldata)
        internal
        virtual
        override
        returns (bytes4, int128)
    {
        (int24 tickLower, int24 lower, int24 upper) = _getCrossedTicks(key.toId(), key.tickSpacing);

        if (lower > upper) return (this.afterSwap.selector, 0);

        // set the last tick lower for the pool
        _tickLowerLasts[key.toId()] = tickLower;

        // note that a zeroForOne swap means that the pool is actually gaining token0, so limit
        // order fills are the opposite of swap fills, hence the inversion below
        bool zeroForOne = !params.zeroForOne;
        for (; lower <= upper; lower += key.tickSpacing) {
            _fillOrder(key, lower, zeroForOne);
        }

        return (this.afterSwap.selector, 0);
    }

function _getFullOffer(StoredOffer storage offer) internal view returns (FullOffer memory) {
    uint32 features = offer.features;
    FullOffer memory fullOffer;

    if (_hasFeature(features, FEATURE_MASK_LISTING_FEE)) {
        (fullOffer.listingFeeBps, fullOffer.listingFeeRecipient) = _getListingFee(offer);
    }

    if (_hasFeature(features, FEATURE_MASK_FINDERS_FEE)) {
        fullOffer.findersFeeBps = _getFindersFee(offer);
    }

    if (_hasFeature(features, FEATURE_MASK_EXPIRY)) {
        fullOffer.expiry = _getExpiry(offer);
    }

    fullOffer.currency = _getERC20CurrencyWithFallback(offer);
    fullOffer.maker = offer.maker;
    fullOffer.amount = offer.amount;

    return fullOffer;
}

