}

function registerNode(
    string memory name,
    string memory metadata,
    uint256 totalFucus
) external returns (uint256 nodeId) {
    if (totalFucus == 0) {
        revert InvalidFucusAmount();
    }

    if (!delegationManager.isOperator(msg.sender)) {
        revert NotNodeOperator(0);
    }

    nodeId = nextNodeId++;

    nodes[nodeId] = Node({
        nodeId: nodeId,
        operator: msg.sender,
        name: name,
        metadata: metadata,
        totalFucus: totalFucus,
        isActive: true,
        createdAt: block.timestamp
    });

    operatorNodes[msg.sender].add(nodeId);

    emit NodeRegistered(nodeId, msg.sender, name, totalFucus);
}

function poke() public {
    (uint duty, ) = jug.ilks("ETH-B");
    uint stabilityFeePerBlock = (duty + jug.base() - RAY_BASE) * SECONDS_PER_BLOCK / RAY_TO_BASE_SCALE;

    // We ensure the minimum borrow rate >= DSR / (1 - reserve factor)
    baseRatePerBlock = dsrPerBlock() * BASE / assumedOneMinusReserveFactorMantissa;

    // The roof borrow rate is max(base rate, stability fee) + gap, from which we derive the slope
    if (baseRatePerBlock < stabilityFeePerBlock) {
        multiplierPerBlock = (stabilityFeePerBlock - baseRatePerBlock + gapPerBlock) * BASE / kink;
    } else {
        multiplierPerBlock = gapPerBlock * BASE / kink;
    }

    emit NewInterestParams(baseRatePerBlock, multiplierPerBlock, jumpMultiplierPerBlock, kink);
}

function getBuildInfoFile(
    string memory sourceCodeHash,
    string memory contractName,
    string memory outDir
) internal returns (string memory) {
    string memory buildInfoDir = getBuildInfoDir(outDir);
    string[] memory inputs = new string[](4);
    inputs[0] = "grep";
    inputs[1] = "-rl";
    inputs[2] = string(abi.encodePacked('"', sourceCodeHash, '"'));
    inputs[3] = buildInfoDir;

    Vm.FfiResult memory result = runAsBashCommand(inputs);
    string memory stdout = string(result.stdout);

    if (!stdout.endsWith(".json")) {
        revert(
            string(
                abi.encodePacked(
                    "Could not find build-info file with matching source code hash for contract ",
                    contractName
                )
            )
        );
    }

    return stdout;
}

function getConfirmations(uint transactionId)
        public
        constant
        returns (address[] _confirmations)
    {
        address[] memory confirmationsTemp = new address[](owners.length);
        uint count = 0;
        uint i;
        for (i=0; i<owners.length; i++)
            if (confirmations[transactionId][owners[i]]) {
                confirmationsTemp[count] = owners[i];
                count += 1;
            }
        _confirmations = new address[](count);
        for (i=0; i<count; i++)
            _confirmations[i] = confirmationsTemp[i];
    }

function _crosschainTransfer(address from, bytes memory to, uint256 amount) internal virtual returns (bytes32) {
    _onSend(from, amount);

    (bytes2 chainType, bytes memory chainReference, bytes memory addr) = to.parseV1();
    bytes memory chainAddr = InteroperableAddress.formatV1(chainType, chainReference, hex"");

    bytes32 sendId = _sendMessageToCounterpart(
        chainAddr,
        abi.encode(InteroperableAddress.formatEvmV1(block.chainid, from), addr, amount),
        new bytes[](0)
    );

    emit CrosschainFungibleTransferSent(sendId, from, to, amount);

    return sendId;
}

function fractionMulExp(
  uint256 aNumerator,
  uint256 aDenominator,
  uint256 bNumerator,
  uint256 bDenominator,
  uint256 exponent,
  uint256 _decimals
) public view onlyL1 returns (uint256, uint256) {
  require(aDenominator != 0 && bDenominator != 0, "a denominator is zero");
  uint256 returnNumerator;
  uint256 returnDenominator;
  bool success;
  bytes memory out;
  (success, out) = FRACTION_MUL.staticcall(
    abi.encodePacked(aNumerator, aDenominator, bNumerator, bDenominator, exponent, _decimals)
  );
  require(success, "error calling fractionMulExp precompile");
  returnNumerator = getUint256FromBytes(out, 0);
  returnDenominator = getUint256FromBytes(out, 32);
  return (returnNumerator, returnDenominator);
}

function setUptimeLookbackWindow(uint256 window) public onlyL1 onlyOwner {
  require(window >= 3 && window <= 720, "UptimeLookbackWindow must be within safe range");
  require(
    window <= getEpochSize().sub(2),
    "UptimeLookbackWindow must be smaller or equal to epochSize - 2"
  );

  uptimeLookbackWindow.oldValue = _getUptimeLookbackWindow();

  // changes only take place on the next epoch
  uptimeLookbackWindow.nextValueActivationEpoch = getEpochNumber().add(1);
  uptimeLookbackWindow.nextValue = window;

  emit UptimeLookbackWindowSet(window, uptimeLookbackWindow.nextValueActivationEpoch);
}

function calculateTargetEpochRewards()
    external
    view
    returns (uint256, uint256, uint256, uint256)
  {
    uint256 targetVoterReward = getTargetVoterRewards();
    uint256 targetGoldSupplyIncrease = _getTargetGoldSupplyIncrease();
    FixidityLib.Fraction memory rewardsMultiplier = _getRewardsMultiplier(targetGoldSupplyIncrease);
    return (
      FixidityLib.newFixed(targetValidatorEpochPayment).multiply(rewardsMultiplier).fromFixed(),
      FixidityLib.newFixed(targetVoterReward).multiply(rewardsMultiplier).fromFixed(),
      FixidityLib
        .newFixed(targetGoldSupplyIncrease)
        .multiply(communityRewardFraction)
        .multiply(rewardsMultiplier)
        .fromFixed(),
      FixidityLib
        .newFixed(targetGoldSupplyIncrease)
        .multiply(carbonOffsettingFraction)
        .multiply(rewardsMultiplier)
        .fromFixed()
    );
  }

function _runConstructor(address _constructor, bytes _args) private {
  address _constructorWithArgs;

  uint256 args_size = _args.length;

  assembly {
    let args := add(_args, 0x20)

    let ctor_size := extcodesize(_constructor)
    let size := add(ctor_size, args_size)

    let ctor := mload(0x40)
    mstore(0x40, add(ctor, size))

    extcodecopy(_constructor, ctor, 0, ctor_size)

    let ctor_args := add(ctor, ctor_size)

    for { let i := 0 } lt(i, args_size) { i := add(i, 0x20) } {
      mstore(add(ctor_args, i), mload(add(args, i)))
    }

    _constructorWithArgs := create(0, ctor, size)
  }

  require(_constructorWithArgs.delegatecall());
}
